      result.push(<ul key={`ul-${k++}`} className="my-1 pl-5">{listItems}</ul>);
      continue;
    }
    if (line.trim() === '') { result.push(<br key={`br-${k++}`} />); i++; continue; }
    result.push(
      <span key={`line-${k++}`}>
        {renderBold(line, k++)}
        {i < lines.length - 1 && lines[i + 1] !== '' && !lines[i + 1].match(/^- /) ? <br /> : null}
      </span>
    );
    i++;
  }
  return result;
}

